# Generated by Kiro using Auto, reviewed by ccharland
BeforeAll {
    $script:ScriptPath = "$PSScriptRoot/../Scripts/Test-SignatureCompliance.ps1"
    # Dot-source the function directly so mocks work in the same scope
    . "$PSScriptRoot/../src/CharlandCustomizations/Public/Test-CCAuthenticodeSignature.ps1"
    $script:CCIsWindows = $true
}

Describe 'Test-SignatureCompliance' -Tag 'Windows' -Skip:(-not $IsWindows) {

    BeforeAll {
        # Create a temp directory with test .ps1 files for each run
        $script:TestDir = Join-Path ([System.IO.Path]::GetTempPath()) "SigComplianceTests_$([guid]::NewGuid().ToString('N'))"
        New-Item -ItemType Directory -Path $script:TestDir | Out-Null
        Set-Content -Path (Join-Path $script:TestDir 'Valid.ps1') -Value '# test file'
        Set-Content -Path (Join-Path $script:TestDir 'Invalid.psm1') -Value '# test module'
        Set-Content -Path (Join-Path $script:TestDir 'NoTimestamp.psd1') -Value '@{ ModuleVersion = "1.0" }'
    }

    AfterAll {
        if (Test-Path $script:TestDir) {
            Remove-Item -Recurse -Force $script:TestDir
        }
    }

    Context 'Path validation' {

        It 'Throws when a provided path does not exist' {
            { Test-CCAuthenticodeSignature -Path 'C:\NonExistent\FakePath' } | Should -Throw '*does not exist*'
        }

        It 'Throws when no matching files are found in a valid but empty directory' {
            $emptyDir = Join-Path $script:TestDir 'EmptySubdir'
            New-Item -ItemType Directory -Path $emptyDir -Force | Out-Null

            { Test-CCAuthenticodeSignature -Path $emptyDir } | Should -Throw '*No files were found*'
        }
    }

    Context 'Signature validation - all files valid with timestamps' {

        BeforeAll {
            Mock Get-AuthenticodeSignature {
                [PSCustomObject]@{
                    Status                 = 'Valid'
                    TimeStamperCertificate = [PSCustomObject]@{ Subject = 'CN=Timestamp Authority' }
                }
            }
        }

        It 'Passes when all signatures are valid and timestamped' {
            $result = Test-CCAuthenticodeSignature -Path $script:TestDir
            $result | Should -BeNullOrEmpty
        }
    }

    Context 'Signature validation - invalid signature detected' {

        BeforeAll {
            Mock Get-AuthenticodeSignature {
                [PSCustomObject]@{
                    Status                 = 'NotSigned'
                    TimeStamperCertificate = $null
                }
            }
        }

        It 'Returns objects with NotSigned status when files have invalid signatures' {
            $results = @(Test-CCAuthenticodeSignature -Path $script:TestDir)
            $results | Should -Not -BeNullOrEmpty
            $results[0].Status | Should -Be 'NotSigned'
        }
    }

    Context 'Signature validation - missing timestamp certificate' {

        BeforeAll {
            Mock Get-AuthenticodeSignature {
                [PSCustomObject]@{
                    Status                 = 'Valid'
                    TimeStamperCertificate = $null
                }
            }
        }

        It 'Returns objects with MissingTimestamp status when timestamp certificate is absent' {
            $results = @(Test-CCAuthenticodeSignature -Path $script:TestDir)
            $results | Should -Not -BeNullOrEmpty
            $results[0].Status | Should -Be 'MissingTimestamp'
        }
    }

    Context 'Output behavior when piped' {

        BeforeAll {
            Mock Get-AuthenticodeSignature {
                [PSCustomObject]@{
                    Status                 = 'HashMismatch'
                    TimeStamperCertificate = $null
                }
            }
        }

        It 'Emits PSCustomObjects with Path and Status properties' {
            $results = @(Test-CCAuthenticodeSignature -Path $script:TestDir)
            $results | Should -Not -BeNullOrEmpty
            $results[0].Path | Should -Not -BeNullOrEmpty
            $results[0].Status | Should -Be 'HashMismatch'
        }
    }

    Context 'Mixed results - some valid, some missing timestamp' {

        BeforeAll {
            $script:CallCount = 0
            Mock Get-AuthenticodeSignature {
                $script:CallCount++
                if ($script:CallCount -eq 1) {
                    [PSCustomObject]@{
                        Status                 = 'Valid'
                        TimeStamperCertificate = [PSCustomObject]@{ Subject = 'CN=TSA' }
                    }
                }
                else {
                    [PSCustomObject]@{
                        Status                 = 'Valid'
                        TimeStamperCertificate = $null
                    }
                }
            }
        }

        BeforeEach {
            $script:CallCount = 0
        }

        It 'Reports failures when at least one file is missing a timestamp even if others pass' {
            $results = @(Test-CCAuthenticodeSignature -Path $script:TestDir)
            $results | Should -Not -BeNullOrEmpty
            $results.Status | Should -Contain 'MissingTimestamp'
        }
    }

    Context 'IncludeExtension filtering' {

        BeforeAll {
            # Add a .txt file that should be ignored
            Set-Content -Path (Join-Path $script:TestDir 'ignored.txt') -Value '# not scanned'
        }

        It 'Only validates files matching the specified extensions' {
            Mock Get-AuthenticodeSignature {
                [PSCustomObject]@{
                    Status                 = 'Valid'
                    TimeStamperCertificate = [PSCustomObject]@{ Subject = 'CN=TSA' }
                }
            }

            $result = Test-CCAuthenticodeSignature -Path $script:TestDir -IncludeExtension '.ps1'
            $result | Should -BeNullOrEmpty

            # Only the single .ps1 file should have been checked
            Should -Invoke Get-AuthenticodeSignature -Times 1 -Exactly
        }
    }
}
